import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { KPI } from '../../components/UI';
import { calcResolutionRate, avgResolutionTime } from '../../utils/helpers';
import LiveMap from '../../components/LiveMap';

export default function AdminPortal() {
  const { complaints } = useApp();
  const [activeTab, setActiveTab] = useState('DASHBOARD');

  const navItems = [
    { key: 'DASHBOARD', label: 'Control Center', icon: '📊', count: 0 },
    { key: 'REGISTRY', label: 'Master Registry', icon: '🗃️', count: 0 }
  ];

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'sans-serif' }}>
      <Sidebar 
        title="Command Headquarters" subtitle="Central Railway Oversight" 
        navItems={navItems} activeTab={activeTab} onTabChange={setActiveTab}
        footerUser={{ name: 'Director General', role: 'HQ Administrator', initials: 'HQ', avatarColor: '#B71C1C' }}
      />

      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: 20 }}>
        {activeTab === 'DASHBOARD' ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16, flex: 1 }}>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 14 }}>
              <KPI title="TOTAL WORLD CASUALTIES" value={complaints.length} />
              <KPI title="GLOBAL RESOLUTION RATE" value={`${calcResolutionRate(complaints)}%`} color="#2E7D32" />
              <KPI title="AVG REFLEX TIME" value={`${avgResolutionTime(complaints)} Mins`} color="#4527A0" />
            </div>
            <div style={{ flex: 1 }}><LiveMap /></div>
          </div>
        ) : (
          <div style={{ background: '#fff', border: '1px solid #DDE3E9', borderRadius: 12, overflow: 'hidden', display: 'flex', flexDirection: 'column', flex: 1 }}>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left', fontSize: 13 }}>
                <thead>
                  <tr style={{ background: '#F7F9FC', borderBottom: '1px solid #DDE3E9', color: '#546E7A' }}>
                    <th style={{ padding: 12 }}>TICKET</th>
                    <th style={{ padding: 12 }}>STATION</th>
                    <th style={{ padding: 12 }}>AREA</th>
                    <th style={{ padding: 12 }}>TYPE</th>
                    <th style={{ padding: 12 }}>STATUS</th>
                    <th style={{ padding: 12 }}>CREW OPERATOR</th>
                  </tr>
                </thead>
                <tbody>
                  {complaints.map(c => (
                    <tr key={c.id} style={{ borderBottom: '1px solid #ECEFF1' }}>
                      <td style={{ padding: 12, fontFamily: 'monospace', fontWeight: 600 }}>{c.customTicketId}</td>
                      <td style={{ padding: 12 }}>{c.station?.name}</td>
                      <td style={{ padding: 12 }}>{c.area}</td>
                      <td style={{ padding: 12 }}>{c.emoji} {c.gtype}</td>
                      <td style={{ padding: 12, fontWeight: 700 }}>{c.status}</td>
                      <td style={{ padding: 12, color: '#4527A0' }}>{c.assignedTo || 'Unassigned'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
